            return false
        }
        if lhs.cachedAt != rhs.cachedAt {
            return false
        }
        if lhs.lastConnectedAt != rhs.lastConnectedAt {
            return false
        }
        if lhs.transportState != rhs.transportState {
            return false
        }
        return true
    }

    public func hash(into hasher: inout Hasher) {
        hasher.combine(fingerprint)
        hasher.combine(name)
        hasher.combine(cachedAt)
        hasher.combine(lastConnectedAt)
        hasher.combine(transportState)
    }
}


