// Note that we don't yet support `indirect` for enums.
// See https://github.com/mozilla/uniffi-rs/issues/396 for further discussion.
/**
 * Notification event from client event loops.
 *
 * Covers events from both `RemoteClient` and `UserClient` in a single
 * FFI-friendly enum. All fingerprints are hex-encoded strings.
 */

public enum FfiEvent {
    
    /**
     * Connecting to the proxy server.
     */
    case connecting
    /**
     * Successfully connected to the proxy.
     */
    case connected(fingerprint: String
    )
    /**
     * Started listening for incoming connections.
     */
    case listening
    /**
     * Noise handshake started.
     */
    case handshakeStart
    /**
     * Noise handshake progress.
     */
    case handshakeProgress(message: String
    )
    /**
     * Noise handshake complete.
     */
    case handshakeComplete
    /**
     * Handshake fingerprint for visual verification.
     */
    case handshakeFingerprint(fingerprint: String, identity: String?
    )
    /**
     * Fingerprint was verified and connection accepted.
     */
    case fingerprintVerified
    /**
     * Fingerprint was rejected.
     */
    case fingerprintRejected(reason: String
    )
    /**
     * Client is ready for credential operations.
     */
    case ready
    /**
     * Credential request was sent.
     */
    case credentialRequestSent(domain: String
    )
    /**
     * Credential was received.
     */
    case credentialReceived
    /**
     * Credential was approved and sent (UserClient).
     */
    case credentialApproved(domain: String?, credentialId: String?
    )
    /**
     * Credential was denied (UserClient).
     */
    case credentialDenied(domain: String?, credentialId: String?
    )
    /**
     * Reconnecting to an existing session.
     */
    case reconnectingToSession(fingerprint: String
    )
    /**
     * A known device reconnected — transport keys refreshed.
     */
    case sessionRefreshed(fingerprint: String
    )
    /**
     * Resolving a rendezvous code.
     */
    case rendezvousResolving(code: String
    )
    /**
     * Rendezvous code resolved to a fingerprint.
     */
    case rendezvousResolved(fingerprint: String
    )
    /**
     * Using PSK mode for connection.
     */
    case pskMode(fingerprint: String
    )
    /**
     * Client disconnected from proxy.
     */
    case disconnected(reason: String?
    )
    /**
     * Attempting to reconnect to proxy.
     */
    case reconnecting(attempt: UInt32
    )
    /**
     * Successfully reconnected to proxy.
     */
    case reconnected
    /**
     * An error occurred.
     */
    case error(message: String, context: String?
    )
}


#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeFfiEvent: FfiConverterRustBuffer {
    typealias SwiftType = FfiEvent

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> FfiEvent {
        let variant: Int32 = try readInt(&buf)
        switch variant {
        
        case 1: return .connecting
        
        case 2: return .connected(fingerprint: try FfiConverterString.read(from: &buf)
        )
        
        case 3: return .listening
        
        case 4: return .handshakeStart
        
        case 5: return .handshakeProgress(message: try FfiConverterString.read(from: &buf)
        )
        
        case 6: return .handshakeComplete
        
        case 7: return .handshakeFingerprint(fingerprint: try FfiConverterString.read(from: &buf), identity: try FfiConverterOptionString.read(from: &buf)
        )
        
        case 8: return .fingerprintVerified
        
        case 9: return .fingerprintRejected(reason: try FfiConverterString.read(from: &buf)
        )
        
        case 10: return .ready
        
        case 11: return .credentialRequestSent(domain: try FfiConverterString.read(from: &buf)
        )
        
        case 12: return .credentialReceived
        
        case 13: return .credentialApproved(domain: try FfiConverterOptionString.read(from: &buf), credentialId: try FfiConverterOptionString.read(from: &buf)
        )
        
        case 14: return .credentialDenied(domain: try FfiConverterOptionString.read(from: &buf), credentialId: try FfiConverterOptionString.read(from: &buf)
        )
        
        case 15: return .reconnectingToSession(fingerprint: try FfiConverterString.read(from: &buf)
        )
        
        case 16: return .sessionRefreshed(fingerprint: try FfiConverterString.read(from: &buf)
        )
        
        case 17: return .rendezvousResolving(code: try FfiConverterString.read(from: &buf)
        )
        
        case 18: return .rendezvousResolved(fingerprint: try FfiConverterString.read(from: &buf)
        )
        
        case 19: return .pskMode(fingerprint: try FfiConverterString.read(from: &buf)
        )
        
        case 20: return .disconnected(reason: try FfiConverterOptionString.read(from: &buf)
        )
        
        case 21: return .reconnecting(attempt: try FfiConverterUInt32.read(from: &buf)
        )
        
        case 22: return .reconnected
        
        case 23: return .error(message: try FfiConverterString.read(from: &buf), context: try FfiConverterOptionString.read(from: &buf)
        )
        
        default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: FfiEvent, into buf: inout [UInt8]) {
        switch value {
        
        
        case .connecting:
            writeInt(&buf, Int32(1))
        
        
        case let .connected(fingerprint):
            writeInt(&buf, Int32(2))
            FfiConverterString.write(fingerprint, into: &buf)
            
        
        case .listening:
            writeInt(&buf, Int32(3))
        
        
        case .handshakeStart:
            writeInt(&buf, Int32(4))
        
        
        case let .handshakeProgress(message):
            writeInt(&buf, Int32(5))
            FfiConverterString.write(message, into: &buf)
            
        
        case .handshakeComplete:
            writeInt(&buf, Int32(6))
        
        
        case let .handshakeFingerprint(fingerprint,identity):
            writeInt(&buf, Int32(7))
            FfiConverterString.write(fingerprint, into: &buf)
            FfiConverterOptionString.write(identity, into: &buf)
            
        
        case .fingerprintVerified:
            writeInt(&buf, Int32(8))
        
        
        case let .fingerprintRejected(reason):
            writeInt(&buf, Int32(9))
            FfiConverterString.write(reason, into: &buf)
            
        
        case .ready:
            writeInt(&buf, Int32(10))
        
        
        case let .credentialRequestSent(domain):
            writeInt(&buf, Int32(11))
            FfiConverterString.write(domain, into: &buf)
            
        
        case .credentialReceived:
            writeInt(&buf, Int32(12))
        
        
        case let .credentialApproved(domain,credentialId):
            writeInt(&buf, Int32(13))
            FfiConverterOptionString.write(domain, into: &buf)
            FfiConverterOptionString.write(credentialId, into: &buf)
            
        
        case let .credentialDenied(domain,credentialId):
            writeInt(&buf, Int32(14))
            FfiConverterOptionString.write(domain, into: &buf)
            FfiConverterOptionString.write(credentialId, into: &buf)
            
        
        case let .reconnectingToSession(fingerprint):
            writeInt(&buf, Int32(15))
            FfiConverterString.write(fingerprint, into: &buf)
            
        
        case let .sessionRefreshed(fingerprint):
            writeInt(&buf, Int32(16))
            FfiConverterString.write(fingerprint, into: &buf)
            
        
