/**
 * FFI-friendly error enum that maps the internal ClientError
 * into 6 categories suitable for cross-language consumption.
 */
public enum RemoteAccessError {

    
    
    case ConnectionFailed(message: String
    )
    case HandshakeFailed(message: String
    )
    case CredentialRequestFailed(message: String
    )
    case SessionError(message: String
    )
    case InvalidArgument(message: String
    )
    case Timeout(message: String
    )
}


#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeRemoteAccessError: FfiConverterRustBuffer {
    typealias SwiftType = RemoteAccessError

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> RemoteAccessError {
        let variant: Int32 = try readInt(&buf)
        switch variant {

        

        
        case 1: return .ConnectionFailed(
            message: try FfiConverterString.read(from: &buf)
            )
        case 2: return .HandshakeFailed(
            message: try FfiConverterString.read(from: &buf)
            )
        case 3: return .CredentialRequestFailed(
            message: try FfiConverterString.read(from: &buf)
            )
        case 4: return .SessionError(
            message: try FfiConverterString.read(from: &buf)
            )
        case 5: return .InvalidArgument(
            message: try FfiConverterString.read(from: &buf)
            )
        case 6: return .Timeout(
            message: try FfiConverterString.read(from: &buf)
            )

         default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: RemoteAccessError, into buf: inout [UInt8]) {
        switch value {

        

        
        
        case let .ConnectionFailed(message):
            writeInt(&buf, Int32(1))
            FfiConverterString.write(message, into: &buf)
            
        
        case let .HandshakeFailed(message):
            writeInt(&buf, Int32(2))
            FfiConverterString.write(message, into: &buf)
            
        
        case let .CredentialRequestFailed(message):
            writeInt(&buf, Int32(3))
            FfiConverterString.write(message, into: &buf)
            
        
        case let .SessionError(message):
            writeInt(&buf, Int32(4))
            FfiConverterString.write(message, into: &buf)
            
        
        case let .InvalidArgument(message):
            writeInt(&buf, Int32(5))
            FfiConverterString.write(message, into: &buf)
            
        
        case let .Timeout(message):
            writeInt(&buf, Int32(6))
            FfiConverterString.write(message, into: &buf)
            
        }
    }
}


